INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message_text`, `status`, `reply_text`, `reply_by`, `reply_at`, `reply_file_path`, `sent_at`) VALUES
(5, 3, 17, 'طلب كشف حساب وليد باعرمه من الماليه و تصفيت مستحقاته علما ان اخر يوم عمل 16-01-2026', 'closed', NULL, NULL, NULL, NULL, '2026-01-19 22:20:12'),
(6, 3, 13, 'ازالة وليد باعرمه من التامين الطبي', 'closed', 'تم الرفع من قبل أحمد الرفاعي', 13, '2026-01-21 11:53:31', NULL, '2026-01-19 22:20:35'),
(7, 19, 3, 'السلام عليكم ورحمة الله وبركاته،\r\n\r\nنأمل من سعادتكم التكرم بالنظر في طلب رفع راتب الموظف/ شوقي احمد عبدالباقي والموظف عبدالسلام ناصر مصلح مسعد  وذلك نظير ما يقدمان من أداء متميز والتزام واضح في العمل، إضافة إلى تحمله لمهام ومسؤوليات تسهم في تحسين سير العمل وتحقيق أهداف الجهة.\r\n\r\nنرجو منكم دراسة الطلب واتخاذ ما ترونه مناسبًا، شاكرين ومقدّرين تعاونكم الدائم.\r\n\r\nوتفضلوا بقبول فائق الاحترام والتقدير.\r\n\r\n*ملاحظه زيادة الراتب 300 ريال لكل موظف', 'open', NULL, NULL, NULL, NULL, '2026-01-20 07:19:38'),
(8, 14, 3, 'السلام عليكم الرجاء تعديل مهنه السائق محمد اسرار رقم هويه 2485653071 من مهنة عامل الى سائق نقل ثقيل', 'closed', 'سيتم العمل على انجاز الموضوع', 3, '2026-01-21 13:47:30', NULL, '2026-01-20 13:50:48'),
(10, 7, 3, 'زيادة راتب الموظف زيد علي محمد حميد 300 ريال الراتب الحالي 2000 وبعد الزيادة 2300\r\n قسم الكاميرات دعم مقابل اقامة للموظف عصام عبدالمعز علي لطف السلمي مبلغ 500 ريال قسم الكاشير', 'open', NULL, NULL, NULL, NULL, '2026-01-24 08:43:43'),
(12, 15, 3, 'هناك مشكلة في اختيار القسم عند نقل العامل من فرع إلى فرع لايقبل أن ينقل الى نفس القسم', 'closed', 'تم حل المشكلة', 3, '2026-01-31 12:14:33', NULL, '2026-01-30 05:03:55'),
(13, 9, 3, 'السلام عليكم بخصوص توظيف الاثنان وهم محمد عارف عيلان عبده و علي محفوظ علي عبده فان قمنا ب استبدالهم بموظفين كانو لدينا في فرع الواحة الى فرع سكاي مول و ايضا الراتب من سكاي فهم موظفين موسمي', 'open', 'الرجاء التوضيح', 3, '2026-02-16 12:07:34', NULL, '2026-02-14 20:01:02'),
(14, 37, 3, 'بدانا العمل على النضام ونحتاج توصية على الموظف محبوب في انها خدماته و سفره للاجازه', 'open', NULL, NULL, NULL, NULL, '2026-03-08 20:43:40'),
(15, 13, 3, 'أرجوا إرسال لي مهام', 'open', NULL, NULL, NULL, NULL, '2026-03-09 10:45:07'),
(16, 7, 3, 'السلام وعليكم نرجو منكم تقديم راتب الموظف طارق فهيم عمر عبدالولي العبسي السبب ظروف مرضية والموظف على الكفالة', 'open', 'لايوجد تقديم راتب .', 3, '2026-03-17 12:40:11', NULL, '2026-03-15 19:23:30');
